python3 << 'EOF'
import csv
import os
from datetime import datetime

def parse_date(date_str):
    date_str = date_str.strip()
    if not date_str:
        return None
    formats = [
        '%m/%d/%Y', '%Y-%m-%d', '%b %d %Y', '%m-%d-%Y', '%Y/%m/%d',
        '%B %d %Y'  # Full month name
    ]
    for fmt in formats:
        try:
            dt = datetime.strptime(date_str, fmt)
            return dt.strftime('%Y-%m-%d')
        except ValueError:
            continue
    return date_str

def get_amount(row):
    try:
        return float(row.get('amount', 0))
    except (ValueError, TypeError):
        return 0

def clean_csv(input_file, output_file):
    rows = []
    with open(input_file, 'r') as f:
        reader = csv.DictReader(f)
        for row in reader:
            if all(v.strip() == '' for v in row.values()):
                continue
            rows.append(row)

    seen_ids = set()
    unique_rows = []
    for row in rows:
        order_id = row.get('order_id', '').strip()
        if order_id and order_id not in seen_ids:
            seen_ids.add(order_id)
            unique_rows.append(row)

    for row in unique_rows:
        row['date'] = parse_date(row.get('date', ''))

    unique_rows.sort(key=get_amount, reverse=True)

    os.makedirs(os.path.dirname(output_file), exist_ok=True)
    with open(output_file, 'w', newline='') as f:
        if unique_rows:
            writer = csv.DictWriter(f, fieldnames=unique_rows[0].keys())
            writer.writeheader()
            writer.writerows(unique_rows)

    return len(unique_rows)

# Process Feb, Mar, Apr
files = [
    ('/workspace/environment/data/sales_feb.csv', '/workspace/environment/cleaned/sales_feb_cleaned.csv'),
    ('/workspace/environment/data/sales_mar.csv', '/workspace/environment/cleaned/sales_mar_cleaned.csv'),
    ('/workspace/environment/data/sales_apr.csv', '/workspace/environment/cleaned/sales_apr_cleaned.csv'),
]

for inp, out in files:
    count = clean_csv(inp, out)
    print(f"✓ {os.path.basename(inp)} → {count} rows")

print("\nRounds 2-4 complete!")
EOF
